import{_ as o,o as s,c as l,ag as a}from"./chunks/framework.CTpQozEL.js";const h=JSON.parse('{"title":"게이트웨이 로깅","description":"로깅 표면, 파일 로그, WS 로그 스타일, 콘솔 형식","frontmatter":{"title":"게이트웨이 로깅","description":"로깅 표면, 파일 로그, WS 로그 스타일, 콘솔 형식"},"headers":[],"relativePath":"gateway/logging.md","filePath":"gateway/logging.md","lastUpdated":null}'),i={name:"gateway/logging.md"};function t(n,e,c,d,r,g){return s(),l("div",null,[...e[0]||(e[0]=[a(`<h1 id="로깅" tabindex="-1">로깅 <a class="header-anchor" href="#로깅" aria-label="Permalink to &quot;로깅&quot;">​</a></h1><p>사용자 대상 개요(CLI + Control UI + 구성)는 <a href="/openclaw-docs-ko/logging">/logging</a>을 참조하십시오.</p><p>OpenClaw에는 두 가지 로그 &quot;표면&quot;이 있습니다:</p><ul><li><strong>콘솔 출력</strong> (터미널 / Debug UI에서 볼 수 있는 것).</li><li><strong>파일 로그</strong> (JSON 라인) 게이트웨이 로거에 의해 작성됨.</li></ul><h2 id="파일-기반-로거" tabindex="-1">파일 기반 로거 <a class="header-anchor" href="#파일-기반-로거" aria-label="Permalink to &quot;파일 기반 로거&quot;">​</a></h2><ul><li>기본 롤링 로그 파일은 <code>/tmp/openclaw/</code> 아래에 있습니다 (하루에 파일 하나): <code>openclaw-YYYY-MM-DD.log</code><ul><li>날짜는 게이트웨이 호스트의 로컬 타임존을 사용합니다.</li></ul></li><li>로그 파일 경로와 수준은 <code>~/.openclaw/openclaw.json</code>을 통해 구성할 수 있습니다: <ul><li><code>logging.file</code></li><li><code>logging.level</code></li></ul></li></ul><p>파일 형식은 줄당 JSON 객체 하나입니다.</p><p>Control UI 로그 탭은 게이트웨이를 통해 이 파일을 tail합니다(<code>logs.tail</code>). CLI도 동일하게 할 수 있습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --follow</span></span></code></pre></div><p><strong>Verbose vs. 로그 수준</strong></p><ul><li><strong>파일 로그</strong>는 <code>logging.level</code>에 의해서만 제어됩니다.</li><li><code>--verbose</code>는 <strong>콘솔 상세도</strong>(및 WS 로그 스타일)에만 영향을 미칩니다; 파일 로그 수준을 올리지 <strong>않습니다</strong>.</li><li>파일 로그에서 verbose 전용 세부 정보를 캡처하려면 <code>logging.level</code>을 <code>debug</code> 또는 <code>trace</code>로 설정합니다.</li></ul><h2 id="콘솔-캡처" tabindex="-1">콘솔 캡처 <a class="header-anchor" href="#콘솔-캡처" aria-label="Permalink to &quot;콘솔 캡처&quot;">​</a></h2><p>CLI는 <code>console.log/info/warn/error/debug/trace</code>를 캡처하여 파일 로그에 기록하고, stdout/stderr에도 인쇄합니다.</p><p>콘솔 상세도를 독립적으로 조정할 수 있습니다:</p><ul><li><code>logging.consoleLevel</code> (기본값 <code>info</code>)</li><li><code>logging.consoleStyle</code> (<code>pretty</code> | <code>compact</code> | <code>json</code>)</li></ul><h2 id="도구-요약-편집" tabindex="-1">도구 요약 편집 <a class="header-anchor" href="#도구-요약-편집" aria-label="Permalink to &quot;도구 요약 편집&quot;">​</a></h2><p>자세한 도구 요약(예: <code>🛠️ Exec: ...</code>)은 민감한 토큰을 콘솔 스트림에 전달하기 전에 마스킹할 수 있습니다. 이것은 <strong>도구 전용</strong>이며 파일 로그를 변경하지 않습니다.</p><ul><li><code>logging.redactSensitive</code>: <code>off</code> | <code>tools</code> (기본값: <code>tools</code>)</li><li><code>logging.redactPatterns</code>: 정규식 문자열 배열 (기본값 재정의) <ul><li>원시 정규식 문자열(자동 <code>gi</code>) 또는 사용자 지정 플래그가 필요한 경우 <code>/pattern/flags</code>를 사용합니다.</li><li>일치는 처음 6자 + 마지막 4자를 유지하여 마스킹합니다(길이 &gt;= 18), 그렇지 않으면 <code>***</code>.</li><li>기본값은 일반적인 키 할당, CLI 플래그, JSON 필드, bearer 헤더, PEM 블록, 인기 있는 토큰 접두사를 커버합니다.</li></ul></li></ul><h2 id="게이트웨이-websocket-로그" tabindex="-1">게이트웨이 WebSocket 로그 <a class="header-anchor" href="#게이트웨이-websocket-로그" aria-label="Permalink to &quot;게이트웨이 WebSocket 로그&quot;">​</a></h2><p>게이트웨이는 두 가지 모드로 WebSocket 프로토콜 로그를 인쇄합니다:</p><ul><li><strong>일반 모드(<code>--verbose</code> 없음)</strong>: &quot;흥미로운&quot; RPC 결과만 인쇄됩니다: <ul><li>오류 (<code>ok=false</code>)</li><li>느린 호출 (기본 임계값: <code>&gt;= 50ms</code>)</li><li>파싱 오류</li></ul></li><li><strong>Verbose 모드(<code>--verbose</code>)</strong>: 모든 WS 요청/응답 트래픽을 인쇄합니다.</li></ul><h3 id="ws-로그-스타일" tabindex="-1">WS 로그 스타일 <a class="header-anchor" href="#ws-로그-스타일" aria-label="Permalink to &quot;WS 로그 스타일&quot;">​</a></h3><p><code>openclaw gateway</code>는 게이트웨이별 스타일 스위치를 지원합니다:</p><ul><li><code>--ws-log auto</code> (기본값): 일반 모드는 최적화됨; verbose 모드는 컴팩트 출력 사용</li><li><code>--ws-log compact</code>: verbose 시 컴팩트 출력 (짝을 이룬 요청/응답)</li><li><code>--ws-log full</code>: verbose 시 전체 프레임별 출력</li><li><code>--compact</code>: <code>--ws-log compact</code>의 별칭</li></ul><p>예제:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 최적화됨 (오류/느린 것만)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 모든 WS 트래픽 표시 (짝을 이룸)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ws-log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compact</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 모든 WS 트래픽 표시 (전체 메타)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ws-log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> full</span></span></code></pre></div><h2 id="콘솔-형식-서브시스템-로깅" tabindex="-1">콘솔 형식 (서브시스템 로깅) <a class="header-anchor" href="#콘솔-형식-서브시스템-로깅" aria-label="Permalink to &quot;콘솔 형식 (서브시스템 로깅)&quot;">​</a></h2><p>콘솔 포매터는 <strong>TTY 인식</strong>이며 일관되고 접두사가 붙은 줄을 인쇄합니다. 서브시스템 로거는 출력을 그룹화하고 스캔 가능하게 유지합니다.</p><p>동작:</p><ul><li>모든 줄에 <strong>서브시스템 접두사</strong> (예: <code>[gateway]</code>, <code>[canvas]</code>, <code>[tailscale]</code>)</li><li><strong>서브시스템 색상</strong> (서브시스템별 안정적) 플러스 수준 색상</li><li><strong>TTY이거나 환경이 리치 터미널로 보일 때 색상</strong> (<code>TERM</code>/<code>COLORTERM</code>/<code>TERM_PROGRAM</code>), <code>NO_COLOR</code> 준수</li><li><strong>단축 서브시스템 접두사</strong>: 선행 <code>gateway/</code> + <code>channels/</code> 제거, 마지막 2 세그먼트 유지 (예: <code>whatsapp/outbound</code>)</li><li><strong>서브시스템별 서브 로거</strong> (자동 접두사 + 구조화된 필드 <code>{ subsystem }</code>)</li><li><strong><code>logRaw()</code></strong> QR/UX 출력용 (접두사 없음, 형식 없음)</li><li><strong>콘솔 스타일</strong> (예: <code>pretty | compact | json</code>)</li><li><strong>파일 로그 수준과 별개의 콘솔 로그 수준</strong> (<code>logging.level</code>이 <code>debug</code>/<code>trace</code>로 설정된 경우 파일은 전체 세부 정보 유지)</li><li><strong>WhatsApp 메시지 본문</strong>은 <code>debug</code>에서 로깅됩니다 (보려면 <code>--verbose</code> 사용)</li></ul><p>이는 기존 파일 로그를 안정적으로 유지하면서 인터랙티브 출력을 스캔 가능하게 합니다.</p>`,31)])])}const k=o(i,[["render",t]]);export{h as __pageData,k as default};
